# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.net.Uri
import android.graphics.BitmapFactory
import kotlinx.android.synthetic.main.activity_share_receiver.*

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        val intent = intent

        if (intent.action == Intent.ACTION_SEND) {
            handleShareIntent(intent)
        }
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                textview_share_receiver.text = sharedText
            }
            "image/*" -> {
                val bitmap = BitmapFactory.decodeStream(intent.getParcelableExtra<Uri>("android.intent.extra-stream")!!.openInputStream())
                imageview_share_receiver.setImageBitmap(bitmap)
            }
        }
    }

}

